SELECT /* @SQLID=SUB0501_01-02_1#Sql005 */ NVL(VER.MAIL_ADDRESS, USE.MAIL_ADDRESS) AS mail_address , USE.USER_NM , BRA.BRANCH_NAME FROM TB_MED_USERS USE LEFT JOIN MEDIATE_BRANCH BRA ON BRA.BROKER_CODE = USE.BROKER_ID AND bra.BROKER_BRANCH_KIND = '00' LEFT JOIN TB_MED_VERIFY_USERS VER ON USE.USER_ID = VER.USER_ID
USE.PRIV_ID IN
#{id}
USE.USER_ID IN
#{id}

SELECT /* @SQLID=SUB0501_01-02_1#Sql007 */ USER_NM, MAIL_ADDRESS FROM TB_MED_USERS
    WHERE
        USER_ID = #{req.userId}

SELECT /* @SQLID=SUB0501_01-02_1#Sql008 */ FILE_DIR FROM TB_MED_TEMP_FILE_DIR
    WHERE FUNC_ID = #{req.funcId}
    AND CAT_ID = #{req.catId}

