INSERT /* @SQLID=SUB0501_01-02_1#Sql002 */ INTO PSITE_T4N_INFO(
    T4N_ID
    , T4N_TITLE
    , T4N_CONTENT
    , T4N_CREATED_AT
    , T4N_FILE1
    , T4N_FILE2
    , T4N_FILE3
    , T4N_CAT1
    , T4N_FILE_COM1
    , T4N_FILE_COM2
    , T4N_FILE_COM3
    , T4N_URL
    , COR_URL_COM
    , COR_REFERENCE_CONDITION
    , COR_DISCLAIMER
    , COR_READ_FLG
    , COR_CREATE_BY
    , COR_UPDATE_DATE
    , COR_UPDATE_BY
)
VALUES (
    SEQ_PSITE_T4_INFO.nextval
    , #{ req.t4nTitle }
    , #{ req.t4nContent }
    , IFA_DATE_UTIL.IFA_GET_DATE
    , #{ req.t4nFile1 }
    , #{ req.t4nFile2 }
    , #{ req.t4nFile3 }
    , #{ req.t4nCat1 }
    , #{ req.t4nFileCom1 }
    , #{ req.t4nFileCom2 }
    , #{ req.t4nFileCom3 }
    , #{ req.t4nUrl }
    , #{ req.corUrlCom }
    , #{ req.corReferenceCondition }
    , #{ req.corDisclaimer }
    , #{ req.corReadFlg }
    , #{ req.corCreateBy }
    , IFA_DATE_UTIL.IFA_GET_DATE
    , #{ req.corUpdateBy })
